// Başlanğıc mətn
let recipe = "Omlet üçün yumurta, süd və pendir lazımdır";

// 1. charAt: Müəyyən indeksdəki simvolu qaytarır
console.log(recipe.charAt(0)); // nəticə: "O"

// 2. charCodeAt: Müəyyən indeksdəki simvolun Unicode dəyərini qaytarır
console.log(recipe.charCodeAt(0)); // nəticə: 79 ("O" üçün)

// 3. concat: Mətnləri birləşdirir
let extra = " və duz";
console.log(recipe.concat(extra)); // nəticə: "Omlet üçün yumurta, süd və pendir lazımdır və duz"

// 4. includes: Mətndə müəyyən bir hissənin olub-olmadığını yoxlayır
console.log(recipe.includes("yumurta")); // nəticə: true

// 5. indexOf: Mətndə müəyyən bir hissənin ilk indeksini qaytarır
console.log(recipe.indexOf("süd")); // nəticə: 15

// 6. lastIndexOf: Mətndə müəyyən bir hissənin son indeksini qaytarır
console.log(recipe.lastIndexOf("və")); // nəticə: 21

// 7. slice: Mətnin müəyyən bir hissəsini kəsib qaytarır
console.log(recipe.slice(0, 5)); // nəticə: "Omlet"

// 8. substring: Mətnin müəyyən bir hissəsini qaytarır (slice ilə oxşar)
console.log(recipe.substring(7, 12)); // nəticə: "üçün"

// 9. substr: Müəyyən indeksdən başlayaraq müəyyən uzunluqda mətn qaytarır
console.log(recipe.substr(7, 5)); // nəticə: "üçün "

// 10. toLowerCase: Mətni kiçik hərflərə çevirir
console.log(recipe.toLowerCase()); // nəticə: "omlet üçün yumurta, süd və pendir lazımdır"

// 11. toUpperCase: Mətni böyük hərflərə çevirir
console.log(recipe.toUpperCase()); // nəticə: "OMLET ÜÇÜN YUMURTA, SÜD VƏ PENDİR LAZIMDIR"

// 12. trim: Mətnin başındakı və sonundakı boşluqları silir
let spacedRecipe = "  Omlet üçün yumurta  ";
console.log(spacedRecipe.trim()); // nəticə: "Omlet üçün yumurta"

// 13. trimStart: Yalnız mətnin başındakı boşluqları silir
console.log(spacedRecipe.trimStart()); // nəticə: "Omlet üçün yumurta  "

// 14. trimEnd: Yalnız mətnin sonundakı boşluqları silir
console.log(spacedRecipe.trimEnd()); // nəticə: "  Omlet üçün yumurta"

// 15. replace: Mətndəki ilk uyğun hissəni dəyişdirir
console.log(recipe.replace("yumurta", "kərə yağı")); // nəticə: "Omlet üçün kərə yağı, süd və pendir lazımdır"

// 16. replaceAll: Mətndəki bütün uyğun hissələri dəyişdirir
console.log(recipe.replaceAll("və", "ilə")); // nəticə: "Omlet üçün yumurta, süd ilə pendir lazımdır"

// 17. split: Mətni müəyyən ayırıcı ilə array-ə bölür
console.log(recipe.split(" ")); // nəticə: ["Omlet", "üçün", "yumurta,", "süd", "və", "pendir", "lazımdır"]

// 18. startsWith: Mətnin müəyyən bir hissə ilə başlayıb-başlamadığını yoxlayır
console.log(recipe.startsWith("Omlet")); // nəticə: true

// 19. endsWith: Mətnin müəyyən bir hissə ilə bitib-bitmədiyini yoxlayır
console.log(recipe.endsWith("lazımdır")); // nəticə: true

// 20. padStart: Mətnin əvvəlinə simvol əlavə edərək uzunluğu artırır
console.log(recipe.padStart(40, "*")); // nəticə: "****Omlet üçün yumurta, süd və pendir lazımdır"

// 21. padEnd: Mətnin sonuna simvol əlavə edərək uzunluğu artırır
console.log(recipe.padEnd(40, "*")); // nəticə: "Omlet üçün yumurta, süd və pendir lazımdır****"

// 22. repeat: Mətni müəyyən sayda təkrarlayır
console.log("Yumurta ".repeat(3)); // nəticə: "Yumurta Yumurta Yumurta "

// 23. match: Mətni müəyyən bir nümunə ilə uyğunlaşdırır
console.log(recipe.match(/\w+/g)); // nəticə: ["Omlet", "üçün", "yumurta", "süd", "və", "pendir", "lazımdır"]

// 24. search: Mətndə müəyyən bir nümunənin ilk indeksini qaytarır
console.log(recipe.search("süd")); // nəticə: 15

// Səhv indeks nümunəsi
console.log(recipe.charAt(100)); // nəticə: ""

// Regex ilə işləmə
console.log(recipe.match(/yoxdur/g)); // nəticə: null

// Böyük mətnlərdə performans
let longRecipe = "yumurta ".repeat(1000);
console.log(longRecipe.split(" ").length); // nəticə: 1000

