// Starting text
let recipe = "Omelette needs eggs, milk, and cheese";

// 1. charAt: Returns the character at a specific index
console.log(recipe.charAt(0)); // Output: "O"

// 2. charCodeAt: Returns the Unicode value of the character at an index
console.log(recipe.charCodeAt(0)); // Output: 79 (for "O")

// 3. concat: Combines strings
let extra = " and salt";
console.log(recipe.concat(extra)); // Output: "Omelette needs eggs, milk, and cheese and salt"

// 4. includes: Checks if a string contains a specific substring
console.log(recipe.includes("eggs")); // Output: true

// 5. indexOf: Returns the first index of a substring
console.log(recipe.indexOf("milk")); // Output: 15

// 6. lastIndexOf: Returns the last index of a substring
console.log(recipe.lastIndexOf("and")); // Output: 21

// 7. slice: Extracts a portion of the string
console.log(recipe.slice(0, 8)); // Output: "Omelette"

// 8. substring: Extracts a portion of the string (similar to slice)
console.log(recipe.substring(9, 14)); // Output: "needs"

// 9. substr: Extracts a portion starting at an index with a length
console.log(recipe.substr(9, 6)); // Output: "needs "

// 10. toLowerCase: Converts the string to lowercase
console.log(recipe.toLowerCase()); // Output: "omelette needs eggs, milk, and cheese"

// 11. toUpperCase: Converts the string to uppercase
console.log(recipe.toUpperCase()); // Output: "OMELETTE NEEDS EGGS, MILK, AND CHEESE"

// 12. trim: Removes whitespace from both ends
let spacedRecipe = "  Omelette needs eggs  ";
console.log(spacedRecipe.trim()); // Output: "Omelette needs eggs"

// 13. trimStart: Removes whitespace from the start
console.log(spacedRecipe.trimStart()); // Output: "Omelette needs eggs  "

// 14. trimEnd: Removes whitespace from the end
console.log(spacedRecipe.trimEnd()); // Output: "  Omelette needs eggs"

// 15. replace: Replaces the first matching substring
console.log(recipe.replace("eggs", "butter")); // Output: "Omelette needs butter, milk, and cheese"

// 16. replaceAll: Replaces all matching substrings
console.log(recipe.replaceAll("and", "&")); // Output: "Omelette needs eggs, milk, & cheese"

// 17. split: Splits the string into an array by a separator
console.log(recipe.split(" ")); // Output: ["Omelette", "needs", "eggs,", "milk,", "and", "cheese"]

// 18. startsWith: Checks if the string starts with a substring
console.log(recipe.startsWith("Omelette")); // Output: true

// 19. endsWith: Checks if the string ends with a substring
console.log(recipe.endsWith("cheese")); // Output: true

// 20. padStart: Pads the start of the string to reach a length
console.log(recipe.padStart(40, "*")); // Output: "****Omelette needs eggs, milk, and cheese"

// 21. padEnd: Pads the end of the string to reach a length
console.log(recipe.padEnd(40, "*")); // Output: "Omelette needs eggs, milk, and cheese****"

// 22. repeat: Repeats the string a specified number of times
console.log("Eggs ".repeat(3)); // Output: "Eggs Eggs Eggs "

// 23. match: Matches the string against a regular expression
console.log(recipe.match(/\w+/g)); // Output: ["Omelette", "needs", "eggs", "milk", "and", "cheese"]

// 24. search: Returns the index of the first match of a regular expression
console.log(recipe.search("milk")); // Output: 15

// Invalid index example
console.log(recipe.charAt(100)); // Output: ""

// Regex handling
console.log(recipe.match(/none/g)); // Output: null

// Performance with large strings
let longRecipe = "eggs ".repeat(1000);
console.log(longRecipe.split(" ").length); // Output: 1000

