// Начальный текст
let recipe = "Омлет требует яйца, молоко и сыр";

// 1. charAt: Возвращает символ на указанном индексе
console.log(recipe.charAt(0)); // Вывод: "О"

// 2. charCodeAt: Возвращает Unicode-код символа на индексе
console.log(recipe.charCodeAt(0)); // Вывод: 1054 (для "О")

// 3. concat: Объединяет строки
let extra = " и соль";
console.log(recipe.concat(extra)); // Вывод: "Омлет требует яйца, молоко и сыр и соль"

// 4. includes: Проверяет, содержит ли строка подстроку
console.log(recipe.includes("яйца")); // Вывод: true

// 5. indexOf: Возвращает первый индекс подстроки
console.log(recipe.indexOf("молоко")); // Вывод: 15

// 6. lastIndexOf: Возвращает последний индекс подстроки
console.log(recipe.lastIndexOf("и")); // Вывод: 21

// 7. slice: Извлекает часть строки
console.log(recipe.slice(0, 5)); // Вывод: "Омлет"

// 8. substring: Извлекает часть строки (похоже на slice)
console.log(recipe.substring(6, 12)); // Вывод: "требует"

// 9. substr: Извлекает часть строки с указанной длиной
console.log(recipe.substr(6, 7)); // Вывод: "требует"

// 10. toLowerCase: Преобразует строку в нижний регистр
console.log(recipe.toLowerCase()); // Вывод: "омлет требует яйца, молоко и сыр"

// 11. toUpperCase: Преобразует строку в верхний регистр
console.log(recipe.toUpperCase()); // Вывод: "ОМЛЕТ ТРЕБУЕТ ЯЙЦА, МОЛОКО И СЫР"

// 12. trim: Удаляет пробелы с обоих концов
let spacedRecipe = "  Омлет требует яйца  ";
console.log(spacedRecipe.trim()); // Вывод: "Омлет требует яйца"

// 13. trimStart: Удаляет пробелы с начала
console.log(spacedRecipe.trimStart()); // Вывод: "Омлет требует яйца  "

// 14. trimEnd: Удаляет пробелы с конца
console.log(spacedRecipe.trimEnd()); // Вывод: "  Омлет требует яйца"

// 15. replace: Заменяет первое совпадение подстроки
console.log(recipe.replace("яйца", "масло")); // Вывод: "Омлет требует масло, молоко и сыр"

// 16. replaceAll: Заменяет все совпадения подстроки
console.log(recipe.replaceAll("и", "&")); // Вывод: "Омлет требует яйца, молоко & сыр"

// 17. split: Разделяет строку на массив по разделителю
console.log(recipe.split(" ")); // Вывод: ["Омлет", "требует", "яйца,", "молоко,", "и", "сыр"]

// 18. startsWith: Проверяет, начинается ли строка с подстроки
console.log(recipe.startsWith("Омлет")); // Вывод: true

// 19. endsWith: Проверяет, заканчивается ли строка подстрокой
console.log(recipe.endsWith("сыр")); // Вывод: true

// 20. padStart: Добавляет символы в начало строки до нужной длины
console.log(recipe.padStart(40, "*")); // Вывод: "****Омлет требует яйца, молоко и сыр"

// 21. padEnd: Добавляет символы в конец строки до нужной длины
console.log(recipe.padEnd(40, "*")); // Вывод: "Омлет требует яйца, молоко и сыр****"

// 22. repeat: Повторяет строку заданное количество раз
console.log("Яйца ".repeat(3)); // Вывод: "Яйца Яйца Яйца "

// 23. match: Сопоставляет строку с регулярным выражением
console.log(recipe.match(/\w+/g)); // Вывод: ["Омлет", "требует", "яйца", "молоко", "и", "сыр"]

// 24. search: Возвращает индекс первого совпадения регулярного выражения
console.log(recipe.search("молоко")); // Вывод: 15

// Пример неверного индекса
console.log(recipe.charAt(100)); // Вывод: ""

// Работа с регулярными выражениями
console.log(recipe.match(/нет/g)); // Вывод: null

// Производительность с большими строками
let longRecipe = "яйца ".repeat(1000);
console.log(longRecipe.split(" ").length); // Вывод: 1000

